import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

const REASONS: Record<string, string> = {
  not_approved: 'Your account is not approved for Oracle.',
  disabled: 'Your Oracle access has been disabled.',
  hijack_attempt:
